1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const itemPremium = (item: { type: string }): number => {
12	  const base = BASE_PREMIUM[item.type];
13	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
14	};
15	
16	export const runScenario = (input: any): { results: unknown[] } => {
17	  const items: { type: string }[] = input.steps[0].items;
18	  const premium =
19	    items.reduce((total, item) => total + itemPremium(item), 0) + PROCESSING_FEE;
20	  return { results: [{ premium }] };
21	};
